--
-- Table structure for table `customer_request_cases`
--

DROP TABLE IF EXISTS `customer_request_cases`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_request_cases` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID yêu cầu',
  `request_code` varchar(50) NOT NULL COMMENT 'Mã yêu cầu',
  `legacy_customer_request_id` bigint unsigned DEFAULT NULL COMMENT 'ID yêu cầu cũ để truy vết',
  `customer_id` bigint unsigned DEFAULT NULL COMMENT 'Khách hàng',
  `customer_personnel_id` bigint unsigned DEFAULT NULL COMMENT 'Người yêu cầu phía khách hàng',
  `support_service_group_id` bigint unsigned DEFAULT NULL COMMENT 'Nhóm hỗ trợ',
  `project_id` bigint unsigned DEFAULT NULL COMMENT 'Dự án liên quan',
  `project_item_id` bigint unsigned DEFAULT NULL COMMENT 'Hạng mục dự án',
  `product_id` bigint unsigned DEFAULT NULL COMMENT 'Sản phẩm liên quan',
  `received_by_user_id` bigint unsigned DEFAULT NULL COMMENT 'Người tiếp nhận ban đầu',
  `requester_name_snapshot` varchar(255) DEFAULT NULL COMMENT 'Tên người yêu cầu chụp tại thời điểm tạo',
  `summary` varchar(500) NOT NULL COMMENT 'Nội dung yêu cầu',
  `description` text COMMENT 'Mô tả chi tiết',
  `priority` tinyint unsigned NOT NULL DEFAULT '2' COMMENT 'Độ ưu tiên 1-4',
  `source_channel` varchar(100) DEFAULT NULL COMMENT 'Kênh tiếp nhận',
  `current_status_code` varchar(80) NOT NULL DEFAULT 'new_intake' COMMENT 'Trạng thái hiện tại',
  `current_status_instance_id` bigint unsigned DEFAULT NULL COMMENT 'ID trạng thái hiện tại',
  `received_at` datetime DEFAULT NULL COMMENT 'Ngày giờ tiếp nhận ban đầu',
  `completed_at` datetime DEFAULT NULL COMMENT 'Ngày hoàn thành',
  `reported_to_customer_at` datetime DEFAULT NULL COMMENT 'Ngày báo khách hàng',
