INSERT INTO `project_types` VALUES (1,'DAU_TU','Đầu tư',NULL,1,3,NULL,9,'2026-03-14 20:46:46','2026-03-14 23:11:36'),(2,'THUE_DICH_VU_DACTHU','Thuê dịch vụ CNTT đặc thù','Dịch vụ CNTT theo yêu cầu riêng: Là dịch vụ được thiết kế, xây dựng hoặc tùy chỉnh đặc thù theo các yêu cầu riêng biệt của bên thuê để phục vụ mục tiêu quản lý, vận hành cụ thể',1,1,NULL,9,'2026-03-14 20:46:46','2026-03-15 13:50:57'),(3,'THUE_DICH_VU_CO_SAN','Thuê dịch vụ CNTT có sẵn','Dịch vụ CNTT sẵn có trên thị trường: Là các dịch vụ đã được nhà cung cấp thiết lập sẵn về tính năng, tiêu chuẩn kỹ thuật và được cung cấp rộng rãi cho nhiều khách hàng.',1,2,NULL,9,'2026-03-14 23:09:06','2026-03-14 23:11:09');
