--

LOCK TABLES `request_worklogs` WRITE;
/*!40000 ALTER TABLE `request_worklogs` DISABLE KEYS */;
/*!40000 ALTER TABLE `request_worklogs` ENABLE KEYS */;
UNLOCK TABLES;

